queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?fieldtrips a :Field_Trips .
    ?fieldtrips p:trip ?trip .
    ?fieldtrips p:Number_of_students ?number_of_students_f .
    FILTER((STR(?number_of_students_f) = "50" || STR(?number_of_students_f) = "50.0"))
    BIND(?trip AS ?o0)
  }
  UNION
  {
    ?studyhalls a :StudyHalls .
    ?studyhalls p:building ?building .
    ?studyhalls p:number_of_students ?number_of_students_f .
    FILTER((STR(?number_of_students_f) = "50" || STR(?number_of_students_f) = "50.0"))
    BIND(?building AS ?o0)
  }
}

